assignments.value:
={{ 'Classify this email. Return ONLY a raw JSON object — no markdown, no backticks, no explanation.
{"type":"meeting_request" or "invoice" or "newsletter" or "follow_up" or "general","priority":"high" or "medium" or "low","summary":"one sentence max","requires_reply":true or false}

From: ' + $json.from_email + '
Subject: ' + $json.subject + '
Body: ' + $json.body_text }}

parameters.jsCode:
const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let cls = {};
try { cls = JSON.parse((raw.match(/\{[\s\S]*\}/) || [raw])[0]); } catch(e) { cls = { type: 'general', priority: 'medium', summary: '', requires_reply: false }; }
const prev = $('Build Classify Prompt').item.json;
return [{ json: {
  email_id:       prev.email_id,
  thread_id:      prev.thread_id,
  from_email:     prev.from_email,
  subject:        prev.subject,
  body_text:      prev.body_text,
  has_attachments:prev.has_attachments,
  email_type:     cls.type || 'general',
  priority:       cls.priority || 'medium',
  summary:        cls.summary || '',
  requires_reply: cls.requires_reply || false
}}];

