={{ 'Extract meeting details. Return ONLY raw JSON (no markdown):
{"title":"string","date":"YYYY-MM-DD","start_time":"HH:MM","end_time":"HH:MM","timezone":"Europe/London","location":"string or null","description":"string","confirmation_reply":"polite reply to sender"}
If unsure about a field use reasonable defaults. Today is ' + $now.toFormat('yyyy-MM-dd') + '.

From: ' + $json.from_email + '
Subject: ' + $json.subject + '
Body: ' + $json.body_text }}

parameters.jsCode:
const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let m = {};
try { m = JSON.parse((raw.match(/\{[\s\S]*\}/) || [raw])[0]); } catch(e) { m = {}; }
const prev = $('Build Meeting Prompt').item.json;
const date = m.date || $now.toFormat('yyyy-MM-dd');
const start = m.start_time || '10:00';
const end   = m.end_time   || '11:00';
const tz    = m.timezone   || 'Europe/London';
return [{ json: {
  email_id:            prev.email_id,
  from_email:          prev.from_email,
  subject:             prev.subject,
  event_title:         m.title || prev.subject || 'Meeting',
  event_description:   m.description || '',
  event_location:      m.location || '',
  event_start:         date + 'T' + start + ':00',
  event_end:           date + 'T' + end   + ':00',
  confirmation_reply:  m.confirmation_reply || 'Thank you — I have added this meeting to the calendar.'
}}];

