assignments.value:
={{ 'You are a professional personal assistant. Draft a reply to the email below. Return ONLY raw JSON (no markdown):
{"draft_subject":"Re: subject","draft_body":"full reply text"}

From: ' + $json.from_email + '
Subject: ' + $json.subject + '
Body: ' + $json.body_text }}

parameters.jsCode:
const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let dr = {};
try { dr = JSON.parse((raw.match(/\{[\s\S]*\}/) || [raw])[0]); } catch(e) { dr = { draft_subject: '', draft_body: raw }; }
const prev = $('Build Draft Prompt').item.json;
return [{ json: {
  email_id:      prev.email_id,
  from_email:    prev.from_email,
  subject:       prev.subject,
  draft_subject: dr.draft_subject || ('Re: ' + prev.subject),
  draft_body:    dr.draft_body || ''
}}];

const emails = $input.all();
const summary = emails.slice(0, 20).map((item, i) => {
  const e = item.json;
  const from    = e.From || e.from || 'Unknown';
  const subj    = e.Subject || e.subject || '(no subject)';
  const snippet = (e.snippet || e.text || '').substring(0, 120);
  return `${i + 1}. From: ${from}\n   Subject: ${subj}\n   Preview: ${snippet}`;
}).join('\n\n');
return [{ json: { email_count: emails.length, email_summary: summary || 'No unread emails.' } }];

const emailData = $('Aggregate Email Data').item.json;
const calItems  = $input.all();
const eventList = calItems.length
  ? calItems.map(item => {
      const e = item.json;
      const title = e.summary || 'Untitled Event';
      const start = e.start?.dateTime || e.start?.date || 'TBD';
      const end   = e.end?.dateTime   || e.end?.date   || '';
      const loc   = e.location ? ` @ ${e.location}` : '';
      return `• ${title}${loc} — ${start}${end ? ' → ' + end : ''}`;
    }).join('\n')
  : 'No events scheduled for today.';
const today  = new Date().toLocaleDateString('en-GB', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const prompt = `You are a professional personal assistant. Create a concise morning briefing for today, ${today}.\n\nUNREAD EMAILS (${emailData.email_count}):\n${emailData.email_summary}\n\nTODAY\'S CALENDAR:\n${eventList}\n\nFormat as:\n1. Priority Actions (emails needing attention)\n2. Today\'s Schedule\n3. Notes / Reminders\n\nBe friendly, professional, and concise — max 400 words.`;
return [{ json: { email_count: emailData.email_count, email_summary: emailData.email_summary, event_list: eventList, prompt } }];

const aiText  = ($input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || 'No digest generated.').replace(/`[^]*`/g, '').trim();
const today   = new Date().toLocaleDateString('en-GB', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const subject = `Your Morning Briefing — ${today}`;
const body    = `<html><body style="font-family:sans-serif;max-width:600px;margin:0 auto;padding:20px"><h2>🗓️ Morning Briefing</h2><p><strong>${today}</strong></p><hr>${aiText.replace(/\n/g, '<br>')}<hr><p style="font-size:11px;color:#888">Sent by your Gmail Secretary</p></body></html>`;
return [{ json: { digest_subject: subject, digest_body: body } }];

const raw = $input.first().json.candidates?.[0]?.content?.parts?.[0]?.text || '{}';
let cmd = {};
try { cmd = JSON.parse((raw.match(/\{[\s\S]*\}/) || [raw])[0]); } catch(e) { cmd = { intent: 'general_query', params: {}, human_response: '' }; }
return [{ json: {
  intent:          cmd.intent || 'general_query',
  params:          cmd.params || {},
  human_response:  cmd.human_response || 'Processing your request...',
  event_title:     cmd.params?.title || '',
  event_date:      cmd.params?.date  || new Date().toISOString().split('T')[0],
  event_time:      cmd.params?.time  || '10:00',
  event_duration:  cmd.params?.duration_minutes || 60,
  event_desc:      cmd.params?.description || '',
  event_id:        cmd.params?.event_id || '',
  search_query:    cmd.params?.query || '',
  send_to:         cmd.params?.to || '',
  send_subject:    cmd.params?.subject || '',
  send_body:       cmd.params?.body || '',
  days_ahead:      cmd.params?.days_ahead || 1
}}];

